return False, None, None, None\n52\t\n53\t    # Get last 30 trading days\n54\t    df_30 = df.tail(30).copy()\n55\t\n56\t    if len(df_30) < 30:\n57\t        return False, None, None, None\n58\t\n59\t    # Split into first 25 days and last 5 days\n60\t    first_25 = df_30.iloc[:25]\n61\t    last_5 = df_30.iloc[25:]\n62\t\n63\t    # Calculate metrics for first 25 days\n64\t    first_25_max_price = first_25['high'].max()\n65\t    first_25_avg_volume = first_25['volume'].mean()\n66\t\n67\t    # Calculate metrics for last 5 days\n68\t    last_5_max_price = last_5['high'].max()\n69\t    last_5_avg_volume = last_5['volume'].mean()\n70\t\n71\t    # Check Condition 1: Price new high (last 5 days max > first 25 days max)\n72\t    price_new_high = last_5_max_price > first_25_max_price\n73\t\n74\t    # Check Condition 2: Volume shrinkage (last 5 days avg < 80% of first 25 days avg)\n75\t    volume_threshold = first_25_avg_volume * 0.8\n76\t    volume_shrinkage = last_5_avg_volume < volume_threshold\n77\t\n78\t    # Calculate the three required metrics\n79\t    # 1. Price change percentage\n80\t    price_change_pct = (last_5_max_price / first_25_max_price - 1) * 100\n81\t\n82\t    # 2. Volume change percentage (negative means shrinkage)\n83\t    volume_change_pct = (last_5_avg_volume / first_25_avg_volume - 1) * 100\n84\t\n85\t    # 3. Divergence degree (difference between price change and volume change)\n86\t    divergence_pct = price_change_pct - volume_change_pct\n87\t\n88\t    # Both conditions must be met\n89\t    meets_criteria = price_new_high and volume_shrinkage\n90\t\n91\t    return meets_criteria, price_change_pct, volume_change_pct, divergence_pct\n92\t\n93\tdef main():\n94\t    print(\"Price-Volume Divergence Detection Demo\")\n95\t    print(\"=\" * 60)\n96\t\n97\t    # Generate sample stocks with divergence pattern\n98\t    sample_stocks = [\n99\t        ('300123', 'divergence'),\n100\t        ('300456', 'divergence'),\n101\t        ('300789', 'divergence'),\n102\t